              v-loading="tableConfig.tableLoading"
              :tableConfig="tableConfig"
              @tablePageForm="getTableForm"
              @setTableCol="getTableCol"
          ></LTTableForm>
        </div>


      </template>


    </LTPages>
    <LTDialog
        v-if="DialogLTMsg.isShow"
        :DialogLTMsg="DialogLTMsg"
        @close="DialogLTMsg.isShow = false">
      <template v-slot:content>
        弹框
      </template>
    </LTDialog>
