        columnWidth: "130",
        // tableColWidth:'155',
        isHiddenSelection: true, // 是否隐藏勾选
        total: 150,
        pageSize: 20,
        currentPage: 1,
      }
    }
  },
  methods: {
    getSearchFields(data) {
      console.log(data);
      if (data.type != 'reset') {
        this.params = {...this.params, ...JSON.parse(JSON.stringify(data))};
      } else { //重置
        this.params = {
          pageSize: 20,
          currentPage: 1
        }
      }
    },
    //表格分页变化回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize;
      this.tableConfig.currentPage = page.pageNum;
      this.$message.success({
        message: "这是‘分页跳转’操作",
        showClose: true,
        duration: 1000,
      });
    },
